const user = {
  name: "سالم",
  age: 25,
  city: "دمشق"
};

console.log(user.name);       // سالم
console.log(user["age"]);   // 25

user.age = 26;                 // تعديل
user.email = "s@mail.com";  // إضافة
delete user.city;              // حذف
console.log(user);

const student = {
  name: "ليلى",
  grades: [90, 85, 95],
  average() {
    const sum = this.grades.reduce((s, g) => s + g, 0);
    return sum / this.grades.length;
  }
};

console.log(student.name + ": متوسطها " + student.average());

const product = {
  title: "حاسوب",
  specs: { ram: "16GB", cpu: "i7" }
};

console.log(product.specs.ram);       // 16GB
console.log(product.seller?.name);    // undefined بلا خطأ

console.log(Object.keys(product));    // ["title", "specs"]
for (const key in product.specs) {
  console.log(key, "=>", product.specs[key]);
}
